CREATE VIEW `ads_read_user_readbook_ed_view` (`dt` COMMENT "阅读时间", `product_id` COMMENT "产品id", `user_id` COMMENT "用户id", `book_id` COMMENT "书籍id", `site_id` COMMENT "语言id", `corever` COMMENT "core的版本号", `mt` COMMENT "平台 0未知 1iphone 4安卓 9书城", `ver` COMMENT "客户端版本号", `current_language` COMMENT "当前语言", `current_language2` COMMENT "注册时语言", `reg_date` COMMENT "注册时间", `reg_days` COMMENT "距离注册时间时长(天)", `reg_country` COMMENT "注册国家", `country_level` COMMENT "国家等级", `appver` COMMENT "app版本", `sex` COMMENT "性别0未知 1男 2女 3保密", `app_id` COMMENT "项目id，core，语言", `book_name` COMMENT "书名", `channel` COMMENT "书籍频道0:其他 1:女频 2：男频 9：图书 -99：其他", `build_time` COMMENT "上架时间", `new_cname` COMMENT "分类名称", `sexy2` COMMENT "书籍上架、下架判断：字段来源novel_book; Sexy2 >= 4 为下架状态，<4 为上架，其中，Sexy涉黄等级 4软下架 5强制下架 ,0 未涉黄;其他具体数字只是涉黄的分级，没有太多参考意义", `book_nature` COMMENT "书籍来源 1：机翻 2：人工 3：原创 4：cp 5：原创拆章 6：翻译拆章 7：原创图书 8：有声书籍 9：cp翻译 0：未知", `sign_type` COMMENT "签约类型 独家：0 买断， 1 A签；非独家：2 B签； 未签约：-1", `normal_chapter_num_f` COMMENT "发布总章节数", `read_chapter_num` COMMENT "阅读章节数", `etl_time` COMMENT "清洗时间")
COMMENT "书籍阅读表（带书籍信息维度的）" AS SELECT `dws`.`a`.`dt`, `dws`.`a`.`product_id`, `dws`.`a`.`user_id`, `dws`.`a`.`book_id`, `dws`.`a`.`site_id`, `dws`.`a`.`corever`, `dws`.`a`.`mt`, `dws`.`a`.`ver`, `dws`.`a`.`current_language`, `dws`.`a`.`current_language2`, `dws`.`a`.`reg_date`, `dws`.`a`.`reg_days`, `dws`.`a`.`reg_country`, `dim`.`b`.`level` AS `country_level`, `dws`.`a`.`appver`, `dws`.`a`.`sex`, `dws`.`a`.`app_id`, `c`.`book_name`, `c`.`channel`, `c`.`build_time`, `c`.`new_cname`, `c`.`sexy2`, `c`.`book_nature`, `c`.`sign_type`, `c`.`normal_chapter_num_f`, `dws`.`a`.`read_chapter_num`, `dws`.`a`.`etl_time`
FROM `dws`.`dws_read_user_readbook_ed` AS `a` LEFT OUTER JOIN `dim`.`dim_countrylevel` AS `b` ON (`dws`.`a`.`product_id` = `dim`.`b`.`product_id`) AND (`dws`.`a`.`reg_country` = `dim`.`b`.`short_name`) LEFT OUTER JOIN (SELECT `dim`.`dim_shuangwen_book_read_consume_info`.`book_id`, `dim`.`dim_shuangwen_book_read_consume_info`.`book_name`, `dim`.`dim_shuangwen_book_read_consume_info`.`Channel`, `dim`.`dim_shuangwen_book_read_consume_info`.`build_time`, `dim`.`dim_shuangwen_book_read_consume_info`.`new_cname`, `dim`.`dim_shuangwen_book_read_consume_info`.`book_nature`, `dim`.`dim_shuangwen_book_read_consume_info`.`normal_chapter_num_f`, `dim`.`dim_shuangwen_book_read_consume_info`.`sexy2`, `dim`.`dim_shuangwen_book_read_consume_info`.`sign_type`
FROM `dim`.`dim_shuangwen_book_read_consume_info`
WHERE `dim`.`dim_shuangwen_book_read_consume_info`.`product_id` NOT IN (8858)) `c` ON `dws`.`a`.`book_id` = `c`.`book_id`;